sys_ui_script.script:
/**
 * Global UI Script
 * Function: NowAssistPanelMessageAutoExpand()
 *
 * Changes per request:
 * 1) No logging, no console wrappers.
 * 2) No bracket-dot access like arr[i].prop or fn().prop (store first, validate, then use).
 * 3) Uses GetTimeNow() for timestamps (with a guarded fallback only if GetTimeNow is not callable).
 *
 * Behavior:
 * - Installs ONCE in window.top (shell)
 * - Continuously monitors DOM + OPEN shadow roots
 * - Forces all rich-text blocks expanded
 * - Hides "Show more" / "Show less"
 */
function NowAssistPanelMessageAutoExpand(options) {
  var shellWin = window;
  try {
    var topWin = window.top;
    if (topWin && topWin.document) shellWin = topWin;
  } catch (e) {
    shellWin = window;
  }

  // Singleton controller stored in shell window
  var existing = null;
  try {
    existing = shellWin["__nowAssistAutoExpandV5"];
  } catch (e2) {
    existing = null;
  }

  if (existing && typeof existing["start"] === "function") {
    existing["start"]();
    return existing;
  }

  options = options || {};

  var CFG = {
    intervalMs: typeof options["intervalMs"] === "number" ? options["intervalMs"] : 300,
    rootRefreshMs: typeof options["rootRefreshMs"] === "number" ? options["rootRefreshMs"] : 1500
  };

  function timeNow()
  {
	return GetTimeNow();
  }

  var state = {
    running: false,
    intervalId: null,
    tickScheduled: false,
    lastRootRefresh: 0,
    searchRoots: [],
    observedTargets: [],
    observers: []
  };

  function isObserved(target) {
    var arr = state["observedTargets"];
    var i = 0;
    for (i = 0; i < arr.length; i += 1) {
      var t = arr[i];
      if (t === target) return true;
    }
    return false;
  }

  function observeTarget(target) {
    if (!target) return;
    if (isObserved(target)) return;

    var MO = null;
    try {
      MO = shellWin["MutationObserver"];
    } catch (e) {
      MO = null;
    }
    if (!MO) return;

    var mo = null;
    try {
      mo = new MO(function () {
        scheduleTick();
      });
    } catch (e2) {
      mo = null;
    }
    if (!mo) return;

    try {
      mo.observe(target, { childList: true, subtree: true, attributes: true });
    } catch (e3) {
      try {
        mo.disconnect();
      } catch (e4) {}
      return;
    }

    state["observedTargets"].push(target);
    state["observers"].push(mo);
  }

  function ensureStyleInjected(doc) {
    if (!doc) return;

    var head = null;
    try {
      head = doc.head;
    } catch (e) {
      head = null;
    }
    if (!head) return;

    var existingStyle = null;
    try {
      existingStyle = doc.getElementById("nowassist-autoexpand-style");
    } catch (e2) {
      existingStyle = null;
    }
    if (existingStyle) return;

    var style = null;
    try {
      style = doc.createElement("style");
    } catch (e3) {
      style = null;
    }
    if (!style) return;

    try {
      style.id = "nowassist-autoexpand-style";
      style.type = "text/css";
      style.appendChild(
        doc.createTextNode(
          ".nowassist-autoexpanded{display:flex !important;max-height:none !important;height:auto !important;overflow:visible !important;-webkit-line-clamp:unset !important;}" +
            ".nowassist-hide-toggle{display:none !important;}"
        )
      );
      head.appendChild(style);
    } catch (e4) {}
  }

  function collectDocuments(rootDoc) {
    var docs = [];
    if (!rootDoc) return docs;

    docs.push(rootDoc);

    var iframes = [];
    try {
      iframes = rootDoc.querySelectorAll("iframe");
    } catch (e) {
      iframes = [];
    }

    var i = 0;
    for (i = 0; i < iframes.length; i += 1) {
      var frame = iframes[i];
      if (!frame) continue;

      var cw = null;
      try {
        cw = frame.contentWindow;
      } catch (e2) {
        cw = null;
      }
      if (!cw) continue;

      var d = null;
      try {
        d = cw.document;
      } catch (e3) {
        d = null;
      }
      if (d) docs.push(d);
    }

    return docs;
  }

  // Deep query across OPEN shadow roots
  function deepQueryAll(root, selector) {
    var results = [];
    if (!root) return results;

    var queue = [root];
    var seen = [];

    function wasSeen(r) {
      var i = 0;
      for (i = 0; i < seen.length; i += 1) {
        var s = seen[i];
        if (s === r) return true;
      }
      return false;
    }

    while (queue.length) {
      var r = queue.shift();
      if (!r) continue;
      if (wasSeen(r)) continue;
      seen.push(r);

      try {
        var found = r.querySelectorAll(selector);
        var fi = 0;
        for (fi = 0; fi < found.length; fi += 1) {
          var f = found[fi];
          if (f) results.push(f);
        }
      } catch (e) {}

      var els = [];
      try {
        els = r.querySelectorAll("*");
      } catch (e2) {
        els = [];
      }

      var j = 0;
      for (j = 0; j < els.length; j += 1) {
        var el = els[j];
        if (!el) continue;

        var sr = null;
        try {
          sr = el.shadowRoot;
        } catch (e3) {
          sr = null;
        }
        if (sr) queue.push(sr);
      }
    }

    return results;
  }

  function refreshRoots(force) {
    var now = timeNow();
    if (!force) {
      var last = state["lastRootRefresh"];
      if (typeof last === "number" && typeof now === "number") {
        if (now - last < CFG["rootRefreshMs"]) return;
      }
    }
    state["lastRootRefresh"] = now;
    state["searchRoots"] = [];

    var topDoc = null;
    try {
      topDoc = shellWin.document;
    } catch (e) {
      topDoc = null;
    }
    if (!topDoc) return;

    var docs = collectDocuments(topDoc);

    var d = 0;
    for (d = 0; d < docs.length; d += 1) {
      var doc = docs[d];
      if (!doc) continue;

      ensureStyleInjected(doc);

      // Observe doc to catch shell re-renders
      var rootNode = null;
      try {
        rootNode = doc.documentElement || doc.body;
      } catch (e2) {
        rootNode = null;
      }
      if (rootNode) observeTarget(rootNode);

      // Direct host selectors (if present)
      var host = null;
      try {
        host = doc.querySelector(
          "sn-cs-control-chat, sn-cs-control-chat-container, sn-now-assist, sn-now-assist-panel, sn-assist-panel, now-assist, now-assist-panel"
        );
      } catch (e3) {
        host = null;
      }

      if (host) {
        var hostSr = null;
        try {
          hostSr = host.shadowRoot;
        } catch (e4) {
          hostSr = null;
        }
        state["searchRoots"].push(hostSr ? hostSr : host);
        continue;
      }

      // Heuristic fallback: find an open shadow root containing our target classes
      var all = [];
      try {
        all = doc.querySelectorAll("*");
      } catch (e5) {
        all = [];
      }

      var i = 0;
      for (i = 0; i < all.length && i < 5000; i += 1) {
        var el = all[i];
        if (!el) continue;

        var sr = null;
        try {
          sr = el.shadowRoot;
        } catch (e6) {
          sr = null;
        }
        if (!sr) continue;

        var looksRelevant = false;
        try {
          looksRelevant =
            !!sr.querySelector(".sn-cs-rich-text-height-wrapper") ||
            !!sr.querySelector(".sn-cs-rich-text-container") ||
            !!sr.querySelector(".now-button-bar-label");
        } catch (e7) {
          looksRelevant = false;
        }

        if (looksRelevant) {
          state["searchRoots"].push(sr);
          break;
        }
      }
    }

    if (!state["searchRoots"].length) {
      state["searchRoots"] = [topDoc];
    }
  }

  function addClass(el, className) {
    if (!el) return;
    var cl = null;
    try {
      cl = el.classList;
    } catch (e) {
      cl = null;
    }
    if (!cl) return;

    try {
      cl.add(className);
    } catch (e2) {}
  }

  function setImportantStyle(el, prop, value) {
    if (!el) return;
    var st = null;
    try {
      st = el.style;
    } catch (e) {
      st = null;
    }
    if (!st) return;

    var sp = null;
    try {
      sp = st.setProperty;
    } catch (e2) {
      sp = null;
    }
    if (typeof sp !== "function") return;

    try {
      sp.call(st, prop, value, "important");
    } catch (e3) {}
  }

  function forceExpand(el) {
    if (!el) return;

    addClass(el, "nowassist-autoexpanded");

    // Also force inline important styles (covers inline resets by components)
    setImportantStyle(el, "display", "flex");
    setImportantStyle(el, "max-height", "none");
    setImportantStyle(el, "height", "auto");
    setImportantStyle(el, "overflow", "visible");
    setImportantStyle(el, "-webkit-line-clamp", "unset");
  }

  function hideShowToggle(labelEl) {
    if (!labelEl) return;

    var txt = "";
    try {
      txt = labelEl.textContent || "";
    } catch (e) {
      txt = "";
    }
    txt = String(txt);
	txt = txt.replace(/\s+/g, " ");
	txt = txt.trim();
	txt = txt.toLowerCase();

    if (txt !== "show more" && txt !== "show less") return;

    var container = null;

    // closest() may not exist; guard it
    var closestFn = null;
    try {
      closestFn = labelEl.closest;
    } catch (e2) {
      closestFn = null;
    }

    if (typeof closestFn === "function") {
      try {
        container = closestFn.call(labelEl, "now-button-bar");
      } catch (e3) {
        container = null;
      }
      if (!container) {
        try {
          container = closestFn.call(labelEl, "button");
        } catch (e4) {
          container = null;
        }
      }
      if (!container) {
        try {
          container = closestFn.call(labelEl, ".now-button-bar");
        } catch (e5) {
          container = null;
        }
      }
    }

    if (!container) {
      try {
        container = labelEl.parentNode;
      } catch (e6) {
        container = null;
      }
    }

    if (!container) return;

    addClass(container, "nowassist-hide-toggle");
    setImportantStyle(container, "display", "none");
  }

  function observeOpenShadowRootsUnder(root) {
    // Find elements under root; if they have open shadowRoot, observe it
    var els = deepQueryAll(root, "*");
    var i = 0;
    for (i = 0; i < els.length; i += 1) {
      var el = els[i];
      if (!el) continue;

      var sr = null;
      try {
        sr = el.shadowRoot;
      } catch (e) {
        sr = null;
      }
      if (sr) observeTarget(sr);
    }
  }

  function enforceInRoot(root) {
    if (!root) return;

    // Expand message bodies
    var targets = deepQueryAll(
      root,
      ".sn-cs-rich-text-height-wrapper.truncateable.expandable, .sn-cs-rich-text-container"
    );
    var i = 0;
    for (i = 0; i < targets.length; i += 1) {
      var t = targets[i];
      if (t) forceExpand(t);
    }

    // Hide toggles
    var labels = deepQueryAll(root, ".now-button-bar-label");
    var j = 0;
    for (j = 0; j < labels.length; j += 1) {
      var lab = labels[j];
      if (lab) hideShowToggle(lab);
    }

    // Observe this root + any open shadow roots beneath it for continuous updates
    observeTarget(root);
    observeOpenShadowRootsUnder(root);
  }

  function scheduleTick() {
    if (state["tickScheduled"]) return;
    state["tickScheduled"] = true;

    var to = null;
    try {
      to = shellWin.setTimeout;
    } catch (e) {
      to = null;
    }
    if (typeof to !== "function") return;

    to(function () {
      state["tickScheduled"] = false;
      tick();
    }, 30);
  }

  function tick() {
    refreshRoots(false);

    var roots = state["searchRoots"];
    var i = 0;
    for (i = 0; i < roots.length; i += 1) {
      var r = roots[i];
      if (r) enforceInRoot(r);
    }
  }

  var controller = {
    start: function () {
      if (state["running"]) return;
      state["running"] = true;

      refreshRoots(true);
      tick();

      // Fallback polling (covers cases where re-renders happen without observable mutations)
      var si = null;
      try {
        si = shellWin.setInterval;
      } catch (e) {
        si = null;
      }
      if (typeof si === "function") {
        state["intervalId"] = si(function () {
          tick();
        }, CFG["intervalMs"]);
      }
    },

    stop: function () {
      state["running"] = false;

      var ci = null;
      try {
        ci = shellWin.clearInterval;
      } catch (e) {
        ci = null;
      }
      if (typeof ci === "function" && state["intervalId"]) {
        ci(state["intervalId"]);
      }
      state["intervalId"] = null;

      var obs = state["observers"];
      var i = 0;
      for (i = 0; i < obs.length; i += 1) {
        var mo = obs[i];
        if (!mo) continue;

        var disc = null;
        try {
          disc = mo.disconnect;
        } catch (e2) {
          disc = null;
        }
        if (typeof disc === "function") {
          try {
            disc.call(mo);
          } catch (e3) {}
        }
      }

      state["observers"] = [];
      state["observedTargets"] = [];
    }
  };

  try {
    shellWin["__nowAssistAutoExpandV5"] = controller;
  } catch (e) {}

  controller.start();
  return controller;
}
